<?php
require_once __DIR__ . '/../bootstrap.php'; require_admin(); $pdo=admin_db(); $adminTitle='Contact Enquiries';
if(isset($_GET['export'])){header('Content-Type:text/csv');header('Content-Disposition: attachment; filename="zetastyle-enquiries.csv"');$out=fopen('php://output','w');fputcsv($out,['Name','Email','Phone','Message','Date']);foreach($pdo->query('SELECT name,email,phone,message,created_at FROM contact_messages ORDER BY id DESC') as $r)fputcsv($out,$r);exit;}
if(isset($_GET['delete'])){$pdo->prepare('DELETE FROM contact_messages WHERE id=:id')->execute([':id'=>(int)$_GET['delete']]);redirect_with(admin_url('enquiries/'),'Enquiry deleted.');}
$search=trim((string)($_GET['search']??''));$where=$search!==''?'WHERE name LIKE :s OR email LIKE :s OR phone LIKE :s OR message LIKE :s':'';$stmt=$pdo->prepare("SELECT * FROM contact_messages {$where} ORDER BY id DESC");if($search!=='')$stmt->bindValue(':s',"%{$search}%");$stmt->execute();$rows=$stmt->fetchAll();require __DIR__.'/../header.php';
?>
<section class="panel"><div class="panel-head"><h2>Messages</h2><form class="search-form"><input name="search" value="<?= e($search); ?>" placeholder="Search enquiries"><button class="admin-btn">Search</button><a class="admin-btn" href="?export=1">Export CSV</a></form></div><div class="table-wrap"><table><thead><tr><th>Name</th><th>Contact</th><th>Message</th><th>Date</th><th>Actions</th></tr></thead><tbody><?php foreach($rows as $row): ?><tr><td><?= e($row['name']); ?></td><td><?= e($row['email']); ?><small><?= e($row['phone']); ?></small></td><td><?= e($row['message']); ?></td><td><?= e($row['created_at']); ?></td><td><a class="danger-link" href="?delete=<?= (int)$row['id']; ?>" data-confirm>Delete</a></td></tr><?php endforeach; ?></tbody></table></div></section>
<?php require __DIR__.'/../footer.php'; ?>
